```
module tt_um_tpu (
    input  wire [7:0] ui_in,
    output wire [7:0] uo_out,
    input  wire [7:0] uio_in,
    output wire [7:0] uio_out,
    output wire [7:0] uio_oe,
    input  wire       ena,
    input  wire       clk,
    input  wire       rst_n
);
    reg signed [7:0] a [0:3];
    reg signed [7:0] b [0:3];

    wire load_en = uio_in[0];
    wire load_sel_b = uio_in[1];
    wire [1:0] load_index = uio_in[3:2];
    wire output_en = uio_in[4];
    wire [1:0] output_sel = uio_in[6:5];

    integer i;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i=0; i<4; i=i+1) begin
                a[i] <= 8'sd0;
                b[i] <= 8'sd0;
            end
        end else if (load_en) begin
            if (load_sel_b)
                b[load_index] <= ui_in;
            else
                a[load_index] <= ui_in;
        end
    end

    wire [1:0] row = output_sel[1:0]; // 0,1,2,3
    wire [7:0] al = $unsigned(a[{row[1], 1'b0}]);
    wire [7:0] ar = $unsigned(a[{row[1], 1'b1}]);
    wire [7:0] bl = $unsigned(b[{1'b0, row[0]}]);
    wire [7:0] br = $unsigned(b[{1'b0, row[0]} + 2'd2]); // ?

    // Actually b indices: col0 uses b0,b2; col1 uses b1,b3. So bl = b[{0,row[0]}] = b[row[0]]; br = b[{1,row[0]}] = b[row[0]+2].
    wire [7:0] bl = $unsigned(b[row[0]]);
    wire [7:0] br = $unsigned(b[row[0] + 2'd2]);

    wire [7:0] selected = al * bl + ar * br;

    assign uo_out = output_en ? selected : 8'd0;
    assign uio_out = {output_en, 7'b0};
    assign uio_oe = 8'b1000_0000;

    wire _unused = &{ena, uio_in[7]};
